VALUES
  ('heelevel3-6f0ba476-moex-00372', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '若甲公司X2年共賒銷$910,000，並提列壞帳費用$6,500，而X1與X2年底之應收帳款餘額 分別為$840,000與$770,000；X1與X2年底之備抵壞帳餘額分別為$42,000與$35,000。請問 在直接法下營業活動之淨現金流量中銷貨收現數為何？', '["$966,500", "$973,000", "$979,500", "$980,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00373', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '綜合損益表中，在其他綜合損益的部分，下列那一項不可重分類至損益？', '["不動產重估增值", "在現金流量避險工具中，當被避險的預期交易影響損益時，所產生的公允價值變動損益", "透過其他綜合損益按公允價值衡量之債務工具投資，其出售或除列時", "國外營運機構結束或出售時，外幣投資匯回國內或轉換本國貨幣之兌換利益或損失"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00374', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司X1年7月1日倉庫失火，存貨損壞嚴重，依會計資料顯示X1年1月1日存貨金額為 $70,000，在X1年1月1日至6月30日之進貨成本為$450,000，銷貨收入為$400,000。若甲 公司之銷貨毛利率約為30%，火災後之存貨價值為$40,000，但自保險理賠中，獲得損失總金 額80%之現金，請問下列何者正確？', '["甲公司得認列因火災造成的非常損失$200,000", "甲公司前2季之銷貨成本為$320,000", "甲公司X1年因火災所造成之淨損失金額為$40,000", "甲公司X1年災害發生前之存貨成本為$170,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00375', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司 X1 年 1 月 1 日取得主管機關之研究發展補助款$500,000，此補助款係供該公司未來 之產品開發計畫，預期研究發展支出於未來5年內平均發生，並且X1年度之研究發展支出 共$300,000，公司估計研究發展總支出為$1,500,000。請問X1年度之政府補助款$500,000應 認列為「政府補助之利益」之金額為：', '["$100,000", "$250,000", "$300,000", "$500,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00376', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司普通股流通股數相關資訊如下： X1年1月1日流通在外股數 2,500,000股 X1年4月1日按市價現金增資發行普通股 400,000股 X1年7月1日購回庫藏股 150,000股 X2年度2月1日發放100%股票股利 假設X1年度財報核准公布日為X2年3月15日，則計算X1年基本每股盈餘時，所使用之 普通股流通在外加權平均股數為何？', '["2,725,000股", "2,750,000股", "3,650,000股", "5,450,000股"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00377', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '在綜合損益表中，當收益和費損的項目重要時，企業應單獨揭露其性質和金額。下列需要單', '["沖減存貨至淨變現價值，或沖減不動產、廠房及設備至 可回收金額（亦即認列資產減損損失），以及該沖減的迴轉（亦即認列減損損失的迴轉利益）", "企業活動的重組損失，以及重組成本負債準備的迴轉（重組損失迴轉利益）", "處分不動 產、廠房及設備項目的損益", "處分投資的損益 ⑤停業單位損益 ⑥無聊的訴訟，估計敗 訴的機率微乎其微（Remote） ⑦其他之負債準備迴轉"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00378', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司111年5月1日收到客戶開立之票據一張，面額為$240,000，利率4%，5個月到期。', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00379', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '年 7 月 1 日公司以此票據向乙銀行貼現，貼現率 7%，若該票據貼現視為無追索權之出 售，則票據貼現損失金額與下列那項答案最接近（答案四捨五入至元）？', '["$412", "$1,218", "$1,612", "$1,870"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 111, "answer_corrected": false, "flags": ["answer_missing"], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00380', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司自110年開始營業，其存貨相關資料如下： 110年 111年 期末存貨–採先進先出法 $4,700,000 $5,100,000 採加權平均法 $4,100,000 $4,300,000 若稅率為20%，則111年底先進先出法之保留盈餘比加權平均法：', '["少$150,000", "多$640,000", "多$150,000", "少$640,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00381', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司於109年1月1日購入乙公司發行的公司債，面額$100,000，票面利率5%，每年12 月31日付息，112年12月31日到期。109年1月1日按$103,480價格加計$205手續費購 入，當日有效利率4%，分類為透過其他綜合損益按公允價值衡量之金融資產。109年12月 31日，當日該債券之公允價值為$105,000。請問109年12月31日「透過其他綜合損益按公 允價值衡量之債務工具投資評價調整」的金額與下列那項答案最接近（答案四捨五入至元）？', '["$2,168", "$2,618", "$4,567", "$6,234"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL)
